  private CellLocation getCurrentCellLocation(NUIForm form, CellLocation subTableFirstCellLocation, List<CellLocation> locs) {
    CellLocation loc = new CellLocation(-1,-1);
    if(locs.size() == 1 || subTableFirstCellLocation == null) {
      loc = locs.get(0);
    } else {
      for(CellLocation _loc : locs) {
        if(form.isSameSubtable(subTableFirstCellLocation,_loc)) {
          loc = _loc;
          break;
        }
      }
    }
    return loc;
  }

